import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"29. Termination Of Employment","description":"","frontmatter":{"title":"29. Termination Of Employment","eba":"Doctors in Training 2022-2026","topics":["wages","employment","termination"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/29-termination-of-employment.md","filePath":"ebas/doctors-in-training/doctor-employment/29-termination-of-employment.md"}'),r={name:"ebas/doctors-in-training/doctor-employment/29-termination-of-employment.md"};function i(s,e,m,c,p,l){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_29-termination-of-employment" tabindex="-1">29. Termination Of Employment <a class="header-anchor" href="#_29-termination-of-employment" aria-label="Permalink to &quot;29. Termination Of Employment&quot;">​</a></h1><p><strong>29.1</strong> The employment of a full-time or part-time Doctor may be terminated:</p><p><strong>(a)</strong> by at least four weeks’ notice given by the Health Service or the Doctor, or four weeks’ wages paid or forfeited as the case may be in lieu of such notice, except that the period of notice may be reduced by agreement (subject to compliance with the NES); or</p><p><strong>(b)</strong> at the end of a period of appointment under a fixed term or maximum term contract; or</p><p><strong>(c)</strong> with written notice by the Health Service in the event of misconduct, malpractice, neglect of duty or breach of any condition of appointment after the Health Service has made careful inquiry into any matter alleged against the Doctor and has heard whatever statement the Doctor may wish to make relative to that matter and against such termination or has given the Doctor a reasonable opportunity to make such a statement. The Doctor may be assisted in making any statement or submission by a representative of the Association.</p><p><strong>(d)</strong> The period of notice to be given by the Health Service pursuant to subclause 29.1(a) above shall be increased by one week if the Doctor is over 45 years of age and has completed at least two years’ continuous service.</p><p><strong>29.2</strong> Casual employment may be terminated with one hour’s notice.</p><p>Plain language terms: resignation, dismissal.</p>',8)])])}const f=t(r,[["render",i]]);export{d as __pageData,f as default};
